const tiger=document.getElementById("hero-tiger"),totalFrames=180,cols=18,rows=10;let currentX=.5,currentY=.5;const smoothing=.15,tigerFrames=[];for(let t=1;t<=180;t++){const e=t.toString().padStart(4,"0"),r=new Image;r.src=`assets/sprites/tiger_head/head.${e}.webp`,tigerFrames.push(r)}document.addEventListener("mousemove",t=>{const e=t.clientX/window.innerWidth,r=t.clientY/window.innerHeight;currentX+=.15*(e-currentX),currentY+=.15*(r-currentY);let n=Math.floor(18*currentX),a=Math.floor(10*currentY);n=Math.max(0,Math.min(17,n)),a=Math.max(0,Math.min(9,a));let i=18*a+n;i=Math.max(0,Math.min(179,i)),tiger.src=tigerFrames[i].src});